<?php $title='Playlists';require __DIR__.'/partials/header.php';?>
<div class="row g-4"><div class="col-lg-4"><div class="card"><div class="card-body"><h1 class="h4">New playlist</h1><form method="post" action="/playlists"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input class="form-control mb-2" name="name" placeholder="Name" required><textarea class="form-control mb-3" name="description" placeholder="Description"></textarea><button class="btn btn-primary">Create</button></form></div></div></div><div class="col-lg-8"><h1 class="h4">Playlists</h1><?php foreach($playlists as $p):?><div class="card mb-3"><div class="card-body"><div class="d-flex justify-content-between"><div><strong><?=e($p['name'])?></strong><small class="text-secondary"> · <?=e((string)$p['video_count'])?> videos · loops indefinitely</small></div><form method="post" action="/playlists/delete" onsubmit="return confirm('Delete this playlist?')"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="playlist_id" value="<?=e((string)$p['id'])?>"><button class="btn btn-sm btn-outline-danger">Delete</button></form></div><form method="post" action="/playlists/videos" class="d-flex gap-2 my-3"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="playlist_id" value="<?=e((string)$p['id'])?>"><select class="form-select form-select-sm" name="video_id" required><option value="">Add video</option><?php foreach($videos as $v):?><option value="<?=e((string)$v['id'])?>"><?=e($v['title'])?></option><?php endforeach?></select><button class="btn btn-sm btn-outline-primary">Add</button></form><ul class="list-group sortable" data-playlist="<?=e((string)$p['id'])?>"><?php foreach($playlistVideos[$p['id']] as $v):?><li class="list-group-item d-flex justify-content-between align-items-center" draggable="true" data-video="<?=e((string)$v['id'])?>"><span><span class="text-secondary me-2">↕</span><?=e($v['title'])?></span><form method="post" action="/playlists/videos/delete"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="playlist_id" value="<?=e((string)$p['id'])?>"><input type="hidden" name="video_id" value="<?=e((string)$v['id'])?>"><button class="btn btn-sm btn-link text-danger">Remove</button></form></li><?php endforeach?></ul></div></div><?php endforeach?></div></div><script>document.querySelectorAll('.sortable').forEach(list=>{let drag;list.addEventListener('dragstart',e=>drag=e.target.closest('li'));list.addEventListener('dragover',e=>{e.preventDefault();let target=e.target.closest('li');if(target&&target!==drag)list.insertBefore(drag,target)});list.addEventListener('dragend',()=>{let fd=new FormData;fd.append('_csrf','<?=e($_SESSION['csrf'])?>');fd.append('playlist_id',list.dataset.playlist);list.querySelectorAll('li').forEach(x=>fd.append('video_ids[]',x.dataset.video));fetch('/playlists/reorder',{method:'POST',body:fd})})})</script><?php require __DIR__.'/partials/footer.php'; ?>
